@api.depends("next_visit", "qa_date", "submission_date")
def _compute_has_dates_this_week(self):
    from datetime import timedelta
    today = fields.Date.context_today(self)
    week_end = today + timedelta(days=7)

    for lead in self:
        has_date_this_week = False

        # Check each date field
        for date_field in [lead.next_visit, lead.qa_date, lead.submission_date]:
            if date_field:
                dt = fields.Datetime.context_timestamp(lead, date_field)
                date_val = dt.date()
                if today <= date_val <= week_end:
                    has_date_this_week = True
                    break

        lead.x_has_dates_this_week = has_date_this_week

